  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "monthly_region_summary_skips_zero_counts"
version = "0.1.0"
edition = "2021"

[lib]
