",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub month: u8,
    pub amount: i32,
}

pub fn summarize_sales(sales: &[Sale]) -> Vec<String> {
    let mut grouped: BTreeMap<&'static str, (i32, usize, u8)> = BTreeMap::new();

    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert((0, 0, sale.month));
        if sale.month < entry.2 {
            entry.2 = sale.month;
        }
        entry.0 += sale.amount;
        entry.1 += 1;
    }

    let mut lines = Vec::new();
    for (region, (total, count, first_month)) in grouped {
        if total <= 0 {
            continue;
        }
        lines.push(format!("{region}: total={total}, avg={}, first_month={first_month}", total / count as i32));
    }
    lines
}

#[cfg(test)]
mod tests {
    use super::{summarize_sales, Sale};

    #[test]
    fn groups_by_region_and_sorts_alphabetically() {
        let sales = [
            Sale { region: "South", month: 5, amount: 12 },
            Sale { region: "North", month: 3, amount: 10 },
            Sale { region: "North", month: 1, amount: 20 },
        ];

        assert_eq!(
            summarize_sales(&sales),
            vec![
                "North: total=30, avg=15, first_month=1",
                "South: total=12, avg=12, first_month=5",
            ]
        );
    }

    #[test]
    fn excludes_regions_with_non_positive_totals() {
        let sales = [
            Sale { region: "East", month: 2, amount: 5 },
            Sale { region: "East", month: 4, amount: -5 },
            Sale { region: "West", month: 1, amount: -3 },
            Sale { region: "West", month: 2, amount: 1 },
        ];

        let summary = summarize_sales(&sales);
        assert!(summary.is_empty());
    }

    #[test]
    fn average_uses_only_positive_entries_for_included_regions() {
        let sales = [
            Sale { region: "Central", month: 6, amount: 10 },
            Sale { region: "Central", month: 4, amount: 0 },
            Sale { region: "Central", month: 2, amount: 20 },
        ];

        assert_eq!(
            summarize_sales(&sales),
            vec!["Central: total=30, avg=15, first_month=2"]
        );
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert((0, 0, sale.month));
        if sale.month < entry.2 {
            entry.2 = sale.month;
        }
        entry.0 += sale.amount;
        entry.1 += 1;
    }
",
      "replace": "    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert((0, 0, sale.month));
        if sale.month < entry.2 {
            entry.2 = sale.month;
        }
        entry.0 += sale.amount;
        if sale.amount > 0 {
            entry.1 += 1;
        }
    }
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs so averages count only positive sales while still excluding non-positive total regions; cargo test passes."
}

{
  "family": "patch_test_pass",
  "case_id": "workflow_state_transition_reopen_rules",
  "bug_category": "state_transitions",
  "difficulty": "hard",
  "user": "In the Rust crate at {project_root}, fix the state transition logic in src/lib.rs so the tests pass. Keep the implementation compact and preserve the existing API.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "workflow_state_transition_reopen_rules"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Review,
    Approved,
    Rejected,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Archive,
    Restore,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;

    for event in events {
        status = match (status, event) {
            (Status::Draft, Event::Submit) => Status::Review,
            (Status::Draft, Event::Archive) => Status::Archived,

            (Status::Review, Event::Approve) => Status::Approved,
            (Status::Review, Event::Reject) => Status::Rejected,
            (Status::Review, Event::Archive) => Status::Archived,

            (Status::Rejected, Event::Revise) => Status::Draft,
            (Status::Rejected, Event::Archive) => Status::Archived,

            (Status::Approved, Event::Archive) => Status::Archived,
            (Status::Approved, Event::Revise) => Status::Draft,

            (Status::Archived, Event::Restore) => Status::Draft,

            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status::*};

    #[test]
    fn happy_path_reaches_approved() {
        assert_eq!(apply_events(&[Submit, Approve]), Approved);
    }

    #[test]
    fn rejected_items_can_be_revised_and_resubmitted() {
        assert_eq!(apply_events(&[Submit, Reject, Revise, Submit]), Review);
    }

    #[test]
    fn approved_items_require_restore_before_revision() {
        assert_eq!(apply_events(&[Submit, Approve, Revise]), Approved);
        assert_eq!(apply_events(&[Submit, Approve, Archive, Restore, Revise]), Draft);
    }

    #[test]
    fn restore_returns_to_prior_active_state() {
        assert_eq!(apply_events(&[Submit, Archive, Restore]), Review);
        assert_eq!(apply_events(&[Submit, Reject, Archive, Restore]), Rejected);
        assert_eq!(apply_events(&[Archive, Restore]), Draft);
    }

    #[test]
    fn archive_is_terminal_until_restore() {
        assert_eq!(apply_events(&[Submit, Archive, Approve, Reject, Revise]), Archived);
    }

    #[test]
    fn duplicate_submits_do_not_change_review_state() {
        assert_eq!(apply_events(&[Submit, Submit, Approve]), Approved);
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;

    for event in events {
        status = match (status, event) {
            (Status::Draft, Event::Submit) => Status::Review,
            (Status::Draft, Event::Archive) => Status::Archived,

            (Status::Review, Event::Approve) => Status::Approved,
            (Status::Review, Event::Reject) => Status::Rejected,
            (Status::Review, Event::Archive) => Status::Archived,

            (Status::Rejected, Event::Revise) => Status::Draft,
            (Status::Rejected, Event::Archive) => Status::Archived,

            (Status::Approved, Event::Archive) => Status::Archived,
            (Status::Approved, Event::Revise) => Status::Draft,

            (Status::Archived, Event::Restore) => Status::Draft,

            _ => status,
        };
    }

    status
}
",
      "replace": "pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;
    let mut archived_from = Status::Draft;

    for event in events {
        status = match (status, event) {
            (Status::Draft, Event::Submit) => Status::Review,
            (Status::Draft, Event::Archive) => {
                archived_from = status;
                Status::Archived
            }

            (Status::Review, Event::Approve) => Status::Approved,
            (Status::Review, Event::Reject) => Status::Rejected,
            (Status::Review, Event::Archive) => {
                archived_from = status;
                Status::Archived
            }

            (Status::Rejected, Event::Revise) => Status::Draft,
            (Status::Rejected, Event::Archive) => {
                archived_from = status;
                Status::Archived
            }

            (Status::Approved, Event::Archive) => {
                archived_from = status;
                Status::Archived
            }

            (Status::Archived, Event::Restore) => archived_from,

            _ => status,
        };
    }

    status
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs so archived items restore to their prior active state, approved items no longer revise directly, and all tests pass."
}

