{
  "family": "patch_test_pass",
  "case_id": "layered_config_cli_override_precedence",
  "bug_category": "config_merge_precedence",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the config merge logic so tests pass. CLI values should only override file/env when they are actually set, while preserving the normal precedence defaults < file < env < cli.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "layered_config_cli_override_precedence"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
}

impl Config {
    pub fn defaults() -> Self {
        Self {
            host: "127.0.0.1".to_string(),
            port: 8080,
            use_tls: false,
        }
    }
}

pub fn merge_config(
    file: PartialConfig,
    env: PartialConfig,
    cli: PartialConfig,
) -> Config {
    let mut cfg = Config::defaults();

    if let Some(host) = file.host {
        cfg.host = host;
    }
    if let Some(port) = file.port {
        cfg.port = port;
    }
    if let Some(use_tls) = file.use_tls {
        cfg.use_tls = use_tls;
    }

    if let Some(host) = env.host {
        cfg.host = host;
    }
    if let Some(port) = env.port {
        cfg.port = port;
    }
    if let Some(use_tls) = env.use_tls {
        cfg.use_tls = use_tls;
    }

    cfg.host = cli.host.unwrap_or_default();
    cfg.port = cli.port.unwrap_or_default();
    cfg.use_tls = cli.use_tls.unwrap_or(false);

    cfg
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cli_overrides_only_specified_fields() {
        let cfg = merge_config(
            PartialConfig {
                host: Some("file.local".into()),
                port: Some(7000),
                use_tls: Some(false),
            },
            PartialConfig {
                host: Some("env.local".into()),
                port: None,
                use_tls: Some(true),
            },
            PartialConfig {
                host: None,
                port: Some(9000),
                use_tls: None,
            },
        );

        assert_eq!(
            cfg,
            Config {
                host: "env.local".into(),
                port: 9000,
                use_tls: true,
            }
        );
