pub struct Booking {
    pub room: &'static str,
    pub start: u32,
    pub end: u32,
    pub cancelled: bool,
}

impl Booking {
    pub fn new(room: &'static str, start: u32, end: u32) -> Self {
        Self {
            room,
            start,
            end,
            cancelled: false,
        }
    }

    pub fn cancelled(room: &'static str, start: u32, end: u32) -> Self {
        Self {
            room,
            start,
            end,
            cancelled: true,
        }
    }
