    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Connect,
    Disconnect,
    Message { urgent: bool },
    Timeout,
    Retry,
}

#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct Session {
    pub connected: bool,
    pub retries: u8,
    pub urgent_seen: bool,
    pub inbox: u32,
    pub dropped: bool,
}

pub fn handle_event(session: &mut Session, event: Event) -> &'static str {
    match event {
        Event::Connect => {
            session.connected = true;
            "connected"
        }
        Event::Disconnect => {
            session.connected = false;
            session.dropped = true;
            "disconnected"
        }
        Event::Message { urgent } => {
            if !session.connected {
                return "ignored";
            }
            session.inbox += 1;
            if urgent {
                "message"
            } else {
                session.urgent_seen = true;
                "urgent"
            }
        }
        Event::Timeout => {
            if session.connected {
                session.dropped = true;
                "timeout"
            } else {
                "idle"
            }
        }
        Event::Retry => {
            session.retries += 1;
